mapper.sql:
tenant_id = #{tenantId} AND deleted = false
AND route_code = #{q.routeCode}
AND ledger_code ILIKE concat('%', #{q.unitCode}, '%')
AND direction = #{q.direction}
AND lane_no = #{q.laneNo}
AND adcode = #{q.adcode}
AND start_stake <= #{q.stake} AND end_stake >= #{q.stake}
AND project_id = #{q.projectId}
